import{_ as a,o,c as i,aw as e}from"./chunks/framework.DLufY-ao.js";const h=JSON.parse('{"title":"Методы FIFO и LIFO","description":"","frontmatter":{},"headers":[],"relativePath":"wiki/dev-commit/theory/data-structures/main/fifo-lifo.md","filePath":"wiki/dev-commit/theory/data-structures/main/fifo-lifo.md"}'),r={name:"wiki/dev-commit/theory/data-structures/main/fifo-lifo.md"};function l(s,t,n,c,d,u){return o(),i("div",null,[...t[0]||(t[0]=[e('<h1 id="методы-fifo-и-lifo" tabindex="-1">Методы FIFO и LIFO <a class="header-anchor" href="#методы-fifo-и-lifo" aria-label="Permalink to &quot;Методы FIFO и LIFO&quot;">​</a></h1><h2 id="информация" tabindex="-1">Информация <a class="header-anchor" href="#информация" aria-label="Permalink to &quot;Информация&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">Определения</p><ul><li><p><strong>FIFO</strong> (First In First Out) - «первый пришёл — первый вышел». Удалить элемент можно только после того, как были убраны все ранее добавленные элементы</p></li><li><p><strong>LIFO</strong> (Last In First Out, «последним пришёл — первым вышел») - последний элемент, добавленный в стек, первым выйдет из стека</p></li></ul></div><h2 id="примеры-использования" tabindex="-1">Примеры использования <a class="header-anchor" href="#примеры-использования" aria-label="Permalink to &quot;Примеры использования&quot;">​</a></h2><ul><li><strong>FIFO</strong> применяется в очередях (например, очередь в банке)</li><li><strong>LIFO</strong> используется в стеках (например, откат действий в текстовом редакторе)</li></ul><h2 id="характеристика" tabindex="-1">Характеристика <a class="header-anchor" href="#характеристика" aria-label="Permalink to &quot;Характеристика&quot;">​</a></h2><ul><li><strong>FIFO</strong> обеспечивает порядок обработки элементов в том же порядке, в котором они были добавлены</li><li><strong>LIFO</strong> позволяет быстро возвращать последнее добавленное значение, что полезно для операций отката</li></ul><h2 id="примеры-реализации" tabindex="-1">Примеры реализации: <a class="header-anchor" href="#примеры-реализации" aria-label="Permalink to &quot;Примеры реализации:&quot;">​</a></h2><ul><li><strong>FIFO</strong> можно реализовать с помощью <code>Queue</code> (очередь)</li><li><strong>LIFO</strong> реализуется через <code>Stack</code> (стек)</li></ul>',9)])])}const m=a(r,[["render",l]]);export{h as __pageData,m as default};
